import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 寶珠 } from '../bujian/sanmaya.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛幢 = (bi) => 菩薩坐身(bi, {
    髮先: true,
    胸瓔滴z: 30.2,
    臂(bi, 筆) {
        const { M, L, C, Qk, S, 骨, 衣, 細, 逸, 陰, 陽 } = 筆;
        // 臂先落（竿與拳後覆其上）：尊右前臂上抬把竿，尊左前臂橫貫把竿於下
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-6.3, 33.4], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.35, 肘帽: true })));
        骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [-0.9, 40.8], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.35, 肘帽: true })));
        // 幢竿：自頂際垂直而下（微斜），蔽先鑿（斷髮縷條帛臂線於竿後）
        {
            const { ctx, u, Y } = bi;
            ctx.save();
            ctx.globalCompositeOperation = 'destination-out';
            ctx.beginPath();
            ctx.moveTo(-7.15 * u, Y(6.6));
            ctx.lineTo(-6.25 * u, Y(6.6));
            ctx.lineTo(-1.75 * u, Y(52.2));
            ctx.lineTo(-2.65 * u, Y(52.2));
            ctx.closePath();
            ctx.fill();
            ctx.restore();
        }
        衣(() => {
            M(-7.0, 7.0);
            L(-2.55, 52.0);
            S();
            M(-6.4, 7.0);
            L(-1.95, 52.0);
            S();
            // 芋頭（竿頭鼓飾）
            M(-7.35, 7.0);
            C(-7.6, 5.4, -7.1, 4.3, -6.4, 4.15);
            S();
            M(-6.05, 7.0);
            C(-5.8, 5.4, -6.0, 4.35, -6.4, 4.15);
            S();
            細(() => { M(-7.3, 6.9); Qk(-6.7, 6.5, -6.1, 6.9); S(); });
            // 吹流：自芋頭而颺於尊右外側，帛尾兩歧（杆意一貫）
            逸(() => {
                M(-7.3, 5.6);
                C(-9.6, 6.6, -11.4, 8.8, -12.3, 11.8);
                S();
                M(-7.4, 6.6);
                C(-9.3, 7.6, -10.7, 9.4, -11.4, 11.9);
                S();
                M(-12.3, 11.8);
                Qk(-12.6, 12.9, -12.2, 13.9);
                S();
                M(-11.4, 11.9);
                Qk(-11.6, 12.8, -11.3, 13.6);
                S();
                細(() => { M(-9.2, 7.6); C(-10.2, 8.8, -10.9, 10.2, -11.2, 11.5); S(); });
            });
        });
        寶珠(bi, -6.7, 2.6, 0.52, 1.5, 3);
        // 拳把竿：尊右拳上、尊左拳下（蔽法自斷竿線）
        側拳(bi, -4.6, 31.8, 2.55, 1.1);
        側拳(bi, -2.9, 40.6, -0.15, 1.1, -1);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-7.4, 32.3, -6.6, 33.2, -5.8, 34.0], [-6.9, 31.7, -6.1, 32.6, -5.3, 33.4]], [-6.4, 32.7]);
            腕釧(bi, [[-0.4, 39.5, -0.9, 40.6, -0.4, 41.8], [0.5, 39.7, 0.0, 40.8, 0.5, 42.0]], [0.2, 40.8]);
        });
    },
});
